import{_ as a,c as e,o as m,b as t}from"./app.81e64653.js";const k='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 19","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 19","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-02-01T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/19/index.md"}',i={},r=t('<div class="stanza"><a href="#s3.19" id="s3.19" class="num">3.19</a><div class="sans"><p>\u092F\u0926\u093E \u0924\u0941 \u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E\u0938\u094D\u0935\u0930\u0942\u092A\u092E\u0938\u094D\u092F \u0928\u093F\u092E\u091C\u094D\u091C\u0924\u093F \u0924\u0926\u093E\u2014</p><blockquote><p><strong>\u0915\u0935\u0930\u094D\u0917\u093E\u0926\u093F\u0937\u0941 \u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u093E\u0926\u094D\u092F\u093E\u0903 \u092A\u0936\u0941\u092E\u093E\u0924\u0930\u0903\u0965\u0967\u096F\u0965</strong></p></blockquote><p>\u0905\u0927\u093F\u0937\u094D\u0920\u093E\u0924\u094D\u0930\u094D\u092F\u094B \u092D\u0935\u0928\u094D\u0924\u0940\u0924\u093F \u0936\u0947\u0937\u0903\u0964</p><blockquote><p>\u092F\u093E \u0938\u093E \u0936\u0915\u094D\u0924\u093F\u0930\u094D\u091C\u0917\u0926\u094D\u0927\u093E\u0924\u0941\u0903 \u0915\u0925\u093F\u0924\u093E \u0938\u092E\u0935\u093E\u092F\u093F\u0928\u0940\u0964<br> \u0907\u091A\u094D\u091B\u093E\u0924\u094D\u0935\u0902 \u0924\u0938\u094D\u092F \u0938\u093E \u0926\u0947\u0935\u093F \u0938\u093F\u0938\u0943\u0915\u094D\u0937\u094B\u0903 \u092A\u094D\u0930\u0924\u093F\u092A\u0926\u094D\u092F\u0924\u0947\u0964<br> \u0938\u0948\u0915\u093E\u092A\u093F \u0938\u0924\u094D\u092F\u0928\u0947\u0915\u0924\u094D\u0935\u0902 \u092F\u0925\u093E \u0917\u091A\u094D\u091B\u0924\u093F \u0924\u091A\u094D\u091B\u0943\u0923\u0941\u0965<br> \u090F\u0935\u092E\u0947\u0924\u0926\u093F\u0924\u093F \u091C\u094D\u091E\u0947\u092F\u0902 \u0928\u093E\u0928\u094D\u092F\u0925\u0947\u0924\u093F \u0938\u0941\u0928\u093F\u0936\u094D\u091A\u093F\u0924\u092E\u094D\u0964<br> \u091C\u094D\u091E\u093E\u092A\u092F\u0928\u094D\u0924\u0940 \u091C\u0917\u0924\u094D\u092F\u0924\u094D\u0930 \u091C\u094D\u091E\u093E\u0928\u0936\u0915\u094D\u0924\u093F\u0930\u094D\u0928\u093F\u0917\u0926\u094D\u092F\u0924\u0947\u0965<br> \u090F\u0935\u092E\u094D\u092D\u0942\u0924\u092E\u093F\u0926\u0902 \u0935\u0938\u094D\u0924\u0941 \u092D\u0935\u0924\u094D\u0935\u093F\u0924\u093F \u092F\u0926\u093E \u092A\u0941\u0928\u0903\u0964<br> \u091C\u093E\u0924\u093E \u0924\u0926\u0948\u0935 \u0924\u0924\u094D\u0924\u0926\u094D\u0935\u0924\u094D\u0915\u0941\u0930\u094D\u0935\u0924\u094D\u092F\u0924\u094D\u0930 \u0915\u094D\u0930\u093F\u092F\u094B\u091A\u094D\u092F\u0924\u0947\u0965<br> \u090F\u0935\u0902 \u0938\u0948\u0937\u093E \u0926\u094D\u0935\u093F\u0930\u0942\u092A\u093E\u092A\u093F \u092A\u0941\u0928\u0930\u094D\u092D\u0947\u0926\u0948\u0930\u0928\u0928\u094D\u0924\u0924\u093E\u092E\u094D\u0964<br> \u0905\u0930\u094D\u0925\u094B\u092A\u093E\u0927\u093F\u0935\u0936\u093E\u0924\u094D\u092A\u094D\u0930\u093E\u092A\u094D\u0924\u093E \u091A\u093F\u0928\u094D\u0924\u093E\u092E\u0923\u093F\u0930\u093F\u0935\u0947\u0936\u094D\u0935\u0930\u0940\u0965<br> \u0924\u0924\u094D\u0930 \u0924\u093E\u0935\u0924\u094D\u0938\u092E\u093E\u092A\u0928\u094D\u0928\u092E\u093E\u0924\u0943\u092D\u093E\u0935\u093E \u0935\u093F\u092D\u093F\u0926\u094D\u092F\u0924\u0947\u0964<br> \u0926\u094D\u0935\u093F\u0927\u093E \u091A \u0928\u0935\u0927\u093E \u091A\u0948\u0935 \u092A\u091E\u094D\u091A\u093E\u0936\u0926\u094D\u0927\u093E \u091A \u092E\u093E\u0932\u093F\u0928\u0940\u0965<br> \u092C\u0940\u091C\u092F\u094B\u0928\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u093E\u0926\u094D\u092D\u0947\u0926\u093E\u0926\u094D\u0926\u094D\u0935\u093F\u0927\u093E \u092C\u0940\u091C\u0902 \u0938\u094D\u0935\u0930\u093E \u092E\u0924\u093E\u0903\u0964<br> \u0915\u093E\u0926\u093F\u092D\u093F\u0936\u094D\u091A \u0938\u094D\u092E\u0943\u0924\u093E \u092F\u094B\u0928\u093F\u0930\u094D\u0928\u0935\u0927\u093E \u0935\u0930\u094D\u0917\u092D\u0947\u0926\u0924\u0903\u0965<br> \u092C\u0940\u091C\u092E\u0924\u094D\u0930 \u0936\u093F\u0935\u0903 \u0936\u0915\u094D\u0924\u093F\u0930\u094D\u092F\u094B\u0928\u093F\u0930\u093F\u0924\u094D\u092F\u092D\u093F\u0927\u0940\u092F\u0924\u0947\u0964<br> \u0935\u0930\u094D\u0917\u093E\u0937\u094D\u091F\u0915\u0935\u093F\u092D\u0947\u0926\u0947\u0928 \u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u093E\u0926\u093F \u091A\u093E\u0937\u094D\u091F\u0915\u092E\u094D\u0965<br> \u092A\u094D\u0930\u0924\u093F\u0935\u0930\u094D\u0923\u0935\u093F\u092D\u0947\u0926\u0947\u0928 \u0936\u0924\u093E\u0930\u094D\u0927\u0915\u093F\u0930\u0923\u094B\u091C\u094D\u091C\u094D\u0935\u0932\u093E\u0964<br> \u0930\u0941\u0926\u094D\u0930\u093E\u0923\u093E\u0902 \u0935\u093E\u091A\u0915\u0924\u094D\u0935\u0947\u0928 \u0924\u0924\u094D\u0938\u0919\u094D\u0916\u094D\u092F\u093E\u0928\u093E\u0902 \u0928\u093F\u0935\u0947\u0936\u093F\u0924\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u092E\u093E\u0932\u093F\u0928\u0940\u0935\u093F\u091C\u092F\u0928\u093F\u0930\u0942\u092A\u093F\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u092A\u093E\u0930\u092E\u0947\u0936\u094D\u0935\u0930\u0940 \u092A\u0930\u093E\u0935\u093E\u0915\u094D \u092A\u094D\u0930\u0938\u0930\u0928\u094D\u0924\u0940\u091A\u094D\u091B\u093E\u091C\u094D\u091E\u093E\u0928\u0915\u094D\u0930\u093F\u092F\u093E\u0930\u0942\u092A\u0924\u093E\u0902 \u0936\u094D\u0930\u093F\u0924\u094D\u0935\u093E \u092C\u0940\u091C\u092F\u094B\u0928\u093F\u0935\u0930\u094D\u0917\u0935\u0930\u094D\u0917\u094D\u092F\u093E\u0926\u093F\u0930\u0942\u092A\u093E \u0936\u093F\u0935\u0936\u0915\u094D\u0924\u093F\u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u093E\u0926\u093F\u0935\u093E\u091A\u0915\u093E\u0926\u093F\u0915\u094D\u0937\u093E\u0928\u094D\u0924\u0930\u0942\u092A\u093E\u0902 \u092E\u093E\u0924\u0943\u0915\u093E\u0924\u094D\u092E\u0924\u093E\u0902 \u0936\u094D\u0930\u093F\u0924\u094D\u0935\u093E \u0938\u0930\u094D\u0935\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0937\u094D\u0935\u0935\u093F\u0915\u0932\u094D\u092A\u0915\u0938\u0935\u093F\u0915\u0932\u094D\u092A\u0915\u0924\u0924\u094D\u0924\u0924\u094D\u0938\u0902\u0935\u0947\u0926\u0928\u0926\u0936\u093E\u0938\u094D\u0935\u0928\u094D\u0924\u0903\u092A\u0930\u093E\u092E\u0930\u094D\u0936\u093E\u0924\u094D\u092E\u0928\u093E \u0938\u094D\u0925\u0942\u0932\u0938\u0942\u0915\u094D\u0937\u094D\u092E\u0936\u092C\u094D\u0926\u093E\u0928\u0941\u0935\u0947\u0927\u0928\u0902 \u0935\u093F\u0926\u0927\u093E\u0928\u093E \u0935\u0930\u094D\u0917\u0935\u0930\u094D\u0917\u094D\u092F\u093E\u0926\u093F\u0926\u0947\u0935\u0924\u093E\u0927\u093F\u0937\u094D\u0920\u093E\u0928\u093E\u0926\u093F\u0926\u094D\u0935\u093E\u0930\u0947\u0923 \u0938\u094D\u092E\u092F\u0939\u0930\u094D\u0937\u092D\u092F\u0930\u093E\u0917\u0926\u094D\u0935\u0947\u0937\u093E\u0926\u093F\u092A\u094D\u0930\u092A\u091E\u094D\u091A\u0902 \u092A\u094D\u0930\u092A\u091E\u094D\u091A\u092F\u0928\u094D\u0924\u094D\u092F\u0938\u0919\u094D\u0915\u0941\u091A\u093F\u0924\u0938\u094D\u0935\u0924\u0928\u094D\u0924\u094D\u0930\u091A\u093F\u0926\u094D\u0918\u0928\u0938\u094D\u0935\u0938\u094D\u0935\u0930\u0942\u092A\u092E\u093E\u0935\u0943\u0923\u094D\u0935\u093E\u0928\u093E \u0938\u0919\u094D\u0915\u0941\u091A\u093F\u0924\u092A\u0930\u0924\u0928\u094D\u0924\u094D\u0930\u0926\u0947\u0939\u093E\u0926\u093F\u092E\u092F\u0924\u094D\u0935\u092E\u093E\u092A\u093E\u0926\u092F\u0924\u093F\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0924\u093F\u092E\u093F\u0930\u094B\u0926\u094D\u0918\u093E\u091F\u0947\u093D\u092A\u093F</p><blockquote><p>\u0915\u0930\u0928\u094D\u0927\u094D\u0930\u091A\u093F\u0924\u093F\u092E\u0927\u094D\u092F\u0938\u094D\u0925\u093E \u092C\u094D\u0930\u0939\u094D\u092E\u092A\u093E\u0936\u093E\u0935\u0932\u092E\u094D\u092C\u093F\u0915\u093E\u0903\u0964<br> \u092A\u0940\u0920\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u094B \u092E\u0939\u093E\u0918\u094B\u0930\u093E \u092E\u094B\u0939\u092F\u0928\u094D\u0924\u094D\u092F\u094B \u092E\u0941\u0939\u0941\u0930\u094D\u092E\u0941\u0939\u0941\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F \u092A\u0942\u0930\u094D\u0935\u092E\u092A\u093F \u0938\u0902\u0935\u093E\u0926\u093F\u0924\u092E\u094D\u0964 \u091C\u094D\u091E\u093E\u0928\u093E\u0927\u093F\u0937\u094D\u0920\u093E\u0928\u0902 \u092E\u093E\u0924\u0943\u0915\u093E (\u0967-\u096A) \u0907\u0924\u093F \u0938\u093E\u092E\u093E\u0928\u094D\u092F\u0947\u0928\u094B\u0915\u094D\u0924\u092E\u093F\u0926\u0902 \u0924\u0941 \u092A\u094D\u0930\u093E\u092A\u094D\u0924\u0924\u0924\u094D\u0924\u094D\u0935\u094B\u093D\u092A\u093F \u092A\u094D\u0930\u092E\u093E\u0926\u094D\u092F\u0928\u094D \u092E\u093E\u0939\u0947\u0936\u094D\u092F\u093E\u0926\u093F\u092D\u093F\u0903 \u092A\u0936\u0941\u091C\u0928\u093E\u0927\u093F\u0937\u094D\u0920\u093E\u0924\u0943\u092D\u0942\u0924\u093E\u092D\u093F\u0930\u092A\u093F \u0936\u092C\u094D\u0926\u093E\u0928\u0941\u0935\u0947\u0927\u0926\u094D\u0935\u093E\u0930\u0947\u0923 \u092E\u094B\u0939\u094D\u092F\u0924 \u0907\u0924\u094D\u092F\u093E\u0936\u092F\u0947\u0928\u0947\u0924\u093F \u0935\u093F\u0936\u0947\u0937\u0903\u0965\u0967\u096F\u0965</p></div><hr><div class="trans"><p>Yad\u0101 tu \u015Buddhavidy\u0101svar\u016Bpamasya nimajjati tad\u0101\u2014</p><blockquote><p><strong>Kavarg\u0101di\u1E63u m\u0101he\u015Bvary\u0101dy\u0101\u1E25 pa\u015Bum\u0101tara\u1E25||19||</strong></p></blockquote><p>Adhi\u1E63\u1E6Dh\u0101tryo bhavant\u012Bti \u015Be\u1E63a\u1E25|</p><blockquote><p>Y\u0101 s\u0101 \u015Baktirjagaddh\u0101tu\u1E25 kathit\u0101 samav\u0101yin\u012B|<br> Icch\u0101tva\u1E41 tasya s\u0101 devi sis\u1E5Bk\u1E63o\u1E25 pratipadyate|<br> Saik\u0101pi satyanekatva\u1E41 yath\u0101 gacchati tacch\u1E5B\u1E47u||<br> Evametaditi j\xF1eya\u1E41 n\u0101nyatheti suni\u015Bcitam|<br> J\xF1\u0101payant\u012B jagatyatra j\xF1\u0101na\u015Baktirnigadyate||<br> Evambh\u016Btamida\u1E41 vastu bhavatviti yad\u0101 puna\u1E25|<br> J\u0101t\u0101 tadaiva tattadvatkurvatyatra kriyocyate||<br> Eva\u1E41 sai\u1E63\u0101 dvir\u016Bp\u0101pi punarbhedairanantat\u0101m|<br> Arthop\u0101dhiva\u015B\u0101tpr\u0101pt\u0101 cint\u0101ma\u1E47irive\u015Bvar\u012B||<br> Tatra t\u0101vatsam\u0101pannam\u0101t\u1E5Bbh\u0101v\u0101 vibhidyate|<br> Dvidh\u0101 ca navadh\u0101 caiva pa\xF1c\u0101\u015Baddh\u0101 ca m\u0101lin\u012B||<br> B\u012Bjayony\u0101tmak\u0101dbhed\u0101ddvidh\u0101 b\u012Bja\u1E41 svar\u0101 mat\u0101\u1E25|<br> K\u0101dibhi\u015Bca sm\u1E5Bt\u0101 yonirnavadh\u0101 vargabhedata\u1E25||<br> B\u012Bjamatra \u015Biva\u1E25 \u015Baktiryonirityabhidh\u012Byate|<br> Varg\u0101\u1E63\u1E6Dakavibhedena m\u0101he\u015Bvary\u0101di c\u0101\u1E63\u1E6Dakam||<br> Prativar\u1E47avibhedena \u015Bat\u0101rdhakira\u1E47ojjval\u0101|<br> Rudr\u0101\u1E47\u0101\u1E41 v\u0101cakatvena tatsa\u1E45khy\u0101n\u0101\u1E41 nive\u015Bit\u0101||</p></blockquote><p>iti \u015Br\u012Bm\u0101lin\u012Bvijayanir\u016Bpitan\u012Bty\u0101 p\u0101rame\u015Bvar\u012B par\u0101v\u0101k prasarant\u012Bcch\u0101j\xF1\u0101nakriy\u0101r\u016Bpat\u0101\u1E41 \u015Britv\u0101 b\u012Bjayonivargavargy\u0101dir\u016Bp\u0101 \u015Biva\u015Baktim\u0101he\u015Bvary\u0101div\u0101cak\u0101dik\u1E63\u0101ntar\u016Bp\u0101\u1E41 m\u0101t\u1E5Bk\u0101tmat\u0101\u1E41 \u015Britv\u0101 sarvapram\u0101t\u1E5B\u1E63vavikalpakasavikalpakatattatsa\u1E41vedanada\u015B\u0101svanta\u1E25par\u0101mar\u015B\u0101tman\u0101 sth\u016Blas\u016Bk\u1E63ma\u015Babd\u0101nuvedhana\u1E41 vidadh\u0101n\u0101 vargavargy\u0101didevat\u0101dhi\u1E63\u1E6Dh\u0101n\u0101didv\u0101re\u1E47a smayahar\u1E63abhayar\u0101gadve\u1E63\u0101diprapa\xF1ca\u1E41 prapa\xF1cayantyasa\u1E45kucitasvatantracidghanasvasvar\u016Bpam\u0101v\u1E5B\u1E47v\u0101n\u0101 sa\u1E45kucitaparatantradeh\u0101dimayatvam\u0101p\u0101dayati| Tadukta\u1E41 \u015Br\u012Btimirodgh\u0101\u1E6De&#39;pi</p><blockquote><p>Karandhracitimadhyasth\u0101 brahmap\u0101\u015B\u0101valambik\u0101\u1E25|<br> P\u012B\u1E6Dhe\u015Bvaryo mah\u0101ghor\u0101 mohayantyo muhurmuhu\u1E25||</p></blockquote><p>iti p\u016Brvamapi sa\u1E41v\u0101ditam| J\xF1\u0101n\u0101dhi\u1E63\u1E6Dh\u0101na\u1E41 m\u0101t\u1E5Bk\u0101 (1-4) iti s\u0101m\u0101nyenoktamida\u1E41 tu pr\u0101ptatattvo&#39;pi pram\u0101dyan m\u0101he\u015By\u0101dibhi\u1E25 pa\u015Bujan\u0101dhi\u1E63\u1E6Dh\u0101t\u1E5Bbh\u016Bt\u0101bhirapi \u015Babd\u0101nuvedhadv\u0101re\u1E47a mohyata ity\u0101\u015Bayeneti vi\u015Be\u1E63a\u1E25||19||</p></div><hr><p>\u041D\u043E <em>(tu)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(sva-r\u016Bpam)</em> \u015Auddhavidy\u0101, \u0438\u043B\u0438 \u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435 <em>(\u015Buddha-vidy\u0101)</em>, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0435\u0435 \u044D\u0442\u043E\u043C\u0443 [Yog\u012B] <em>(asya)</em>, \u043F\u043E\u0433\u0440\u0443\u0436\u0430\u0435\u0442\u0441\u044F \u0432\u043D\u0438\u0437 <em>(nimajjati)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>\u2014</p><blockquote><p><strong>M\u0101he\u015Bvar\u012B <em>(m\u0101he\u015Bvar\u012B)</em> \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0431\u043E\u0433\u0438\u043D\u0438 <em>(\u0101dy\u0101\u1E25)</em>, [\u0447\u044C\u0435\u0439 \u0441\u0444\u0435\u0440\u043E\u0439 \u0432\u043B\u0438\u044F\u043D\u0438\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] &quot;ka&quot; <em>(ka)</em> \u0433\u0440\u0443\u043F\u043F\u0430 <em>(varga)</em>, \u0438 \u0442.\u0434. <em>(\u0101di\u1E63u)</em>, [\u0438 \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u0435\u0441\u044F] \u043C\u0430\u0442\u0435\u0440\u044F\u043C\u0438 <em>(m\u0101tara\u1E25)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(pa\u015Bu)</em>, [\u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u0435\u0433\u043E \u0433\u043B\u0430\u0432\u043D\u044B\u043C\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0430\u043C\u0438]||19||</strong></p></blockquote><p>&quot;[\u042D\u0442\u0438 \u0431\u043E\u0433\u0438\u043D\u0438] \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F <em>(bhavanti)</em> [\u0435\u0433\u043E --\u0442\u0430\u043A\u043E\u0433\u043E Yog\u012B--] \u0433\u043B\u0430\u0432\u043D\u044B\u043C\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0430\u043C\u0438 <em>(adhi\u1E63\u1E6Dh\u0101trya\u1E25... iti)</em>&quot;, \u044D\u0442\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0434\u043E\u0431\u0430\u0432\u0438\u0442\u044C [\u043A \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0443 \u0434\u043B\u044F \u043F\u043E\u043B\u043D\u043E\u0442\u044B \u0441\u043C\u044B\u0441\u043B\u0430] <em>(iti \u015Be\u1E63a\u1E25)</em>|</p><blockquote><p>&quot;\u0413\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F <em>(kathit\u0101)</em>, \u0447\u0442\u043E \u044D\u0442\u0430 <em>(y\u0101 s\u0101)</em> \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em> \u0421\u043E\u0437\u0434\u0430\u0442\u0435\u043B\u044F <em>(dh\u0101tu\u1E25)</em> \u043C\u0438\u0440\u0430 <em>(jagat)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u0440\u0438\u0441\u0443\u0449\u0435\u0439 <em>(samav\u0101yin\u012B)</em> [\u0415\u043C\u0443]. \u041E \u0411\u043E\u0433\u0438\u043D\u044F <em>(devi)</em>!, \u041E\u043D\u0430 <em>(s\u0101)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(pratipadyate)</em> \u0412\u043E\u043B\u0435\u0439 <em>(icch\u0101tvam)</em> \u044D\u0442\u043E\u0433\u043E [\u0421\u043E\u0437\u0434\u0430\u0442\u0435\u043B\u044F] <em>(tasya)</em>, [\u043A\u043E\u0433\u0434\u0430] \u041E\u043D \u0436\u0435\u043B\u0430\u0435\u0442 \u043F\u0440\u043E\u044F\u0432\u0438\u0442\u044C <em>(sis\u1E5Bk\u1E63o\u1E25)</em> [\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0443\u044E]. \u0421\u043B\u0443\u0448\u0430\u0439 <em>(tad \u015B\u1E5B\u1E47u)</em>, \u043A\u0430\u043A <em>(yath\u0101)</em> \u041E\u043D\u0430 <em>(s\u0101)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(gacchati)</em> \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C <em>(anekatvam)</em>, \u043D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E <em>(api)</em> \u041E\u043D\u0430 <em>(sat\u012B)</em> \u043E\u0434\u043D\u0430 <em>(ek\u0101)</em>:</p></blockquote><blockquote><p>\u041E\u0431\u044A\u044F\u0432\u043B\u044F\u044F <em>(j\xF1\u0101payant\u012B)</em> \u0441 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E <em>(suni\u015Bcitam)</em>, \u0447\u0442\u043E &#39;\u042D\u0442\u043E <em>(etad)</em> \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0435, \u0438\u043B\u0438 \u043E\u0431\u044A\u0435\u043A\u0442 <em>(j\xF1eyam)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u044D\u0442\u043E\u043C\u0443 <em>(evam... iti)</em>, [\u0438] \u043D\u0435 <em>(na)</em> \u0438\u043D\u0430\u0447\u0435 <em>(anyath\u0101... iti)</em>!&#39;, \u041E\u043D\u0430 \u0437\u043E\u0432\u0435\u0442\u0441\u044F <em>(nigadyate)</em> \u0421\u0438\u043B\u043E\u0439 \u0417\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na-\u015Bakti\u1E25)</em> \u0432 \u044D\u0442\u043E\u043C \u043C\u0438\u0440\u0435 <em>(jagati atra)</em>.</p></blockquote><blockquote><p>\u041E\u0434\u043D\u0430\u043A\u043E <em>(punar)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u041E\u043D\u0430 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u043E\u0439 <em>(j\u0101t\u0101)</em> [\u043A\u0430\u043A] &#39;\u041F\u0443\u0441\u0442\u044C \u044D\u0442\u0430 \u0432\u0435\u0449\u044C \u0441\u0442\u0430\u043D\u0435\u0442 <em>(idam vastu bhavatu)</em> \u0442\u0430\u043A\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(evam-bh\u016Btam... iti)</em>!&#39;, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101 eva)</em>, \u0441\u043E\u0437\u0434\u0430\u0432\u0430\u044F <em>(kurvat\u012B)</em> \u044D\u0442\u0443 [\u0432\u0435\u0449\u044C] <em>(tad)</em> \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(tad-vat)</em> \u0437\u0434\u0435\u0441\u044C <em>(atra)</em>, \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F, \u0447\u0442\u043E \u041E\u043D\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(ucyate)</em> [\u0421\u0438\u043B\u043E\u0439] \u0414\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(kriy\u0101)</em>.</p></blockquote><blockquote><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u0445\u043E\u0442\u044F <em>(api)</em> \u044D\u0442\u0430 \u0441\u0430\u043C\u0430\u044F [\u015Aakti] <em>(s\u0101 e\u1E63\u0101)</em> \u0438\u043C\u0435\u0435\u0442 \u0434\u0432\u0435 [\u0433\u043B\u0430\u0432\u043D\u044B\u0435] \u0444\u043E\u0440\u043C\u044B <em>(dvi-r\u016Bp\u0101)</em>, \u041E\u043D\u0430 \u043F\u0440\u0435\u0442\u0435\u0440\u043F\u0435\u0432\u0430\u0435\u0442 <em>(pr\u0101pt\u0101)</em> \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u044B\u0435 <em>(anantat\u0101m)</em> \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F <em>(bhedai\u1E25)</em>, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E <em>(va\u015B\u0101t)</em> \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0430\u043C <em>(up\u0101dhi)</em> [\u0436\u0435\u043B\u0430\u0435\u043C\u044B\u0445] \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(artha)</em>. [\u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u044D\u0442\u0430] \u0413\u043E\u0441\u043F\u043E\u0436\u0430 <em>(\u012B\u015Bvar\u012B)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u0430 <em>(iva)</em> \u0434\u0440\u0430\u0433\u043E\u0446\u0435\u043D\u043D\u043E\u043C\u0443 \u043A\u0430\u043C\u043D\u044E <em>(cint\u0101-ma\u1E47i\u1E25)</em> --\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0438\u0441\u043F\u043E\u043B\u043D\u044F\u0435\u0442 \u0432\u0441\u0435 \u0436\u0435\u043B\u0430\u043D\u0438\u044F \u0435\u0433\u043E \u043E\u0431\u043B\u0430\u0434\u0430\u0442\u0435\u043B\u044F--.</p></blockquote><blockquote><p>\u0417\u0430\u0442\u0435\u043C <em>(tatra)</em>, [\u043A\u043E\u0433\u0434\u0430 \u0413\u043E\u0441\u043F\u043E\u0436\u0430] \u0432\u043D\u0430\u0447\u0430\u043B\u0435 \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(t\u0101vat sam\u0101panna... bh\u0101v\u0101)</em> \u043C\u0430\u0442\u0435\u0440\u0438 <em>(m\u0101t\u1E5B)</em>, \u041E\u043D\u0430 \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F <em>(vibhidyate)</em> \u0434\u0432\u0443\u043C\u044F \u043F\u0443\u0442\u044F\u043C\u0438 <em>(dvidh\u0101)</em> \u0438 <em>(ca... ca eva)</em> \u0434\u0435\u0432\u044F\u0442\u044C\u044E \u043F\u0443\u0442\u044F\u043C\u0438 <em>(navadh\u0101)</em>, \u0438 <em>(ca)</em> [\u043A\u043E\u0433\u0434\u0430 \u0442\u0430\u043A\u0430\u044F \u0413\u043E\u0441\u043F\u043E\u0436\u0430 \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F] \u043F\u044F\u0442\u044C\u044E\u0434\u0435\u0441\u044F\u0442\u044C\u044E \u043F\u0443\u0442\u044F\u043C\u0438 <em>(pa\xF1c\u0101\u015Baddh\u0101)</em>, [\u041E\u043D\u0430 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F] \u043D\u043E\u0441\u0438\u0442\u0435\u043B\u0435\u043C \u0433\u0438\u0440\u043B\u044F\u043D\u0434\u044B <em>(m\u0101lin\u012B)</em>, [\u0441\u0434\u0435\u043B\u0430\u043D\u043D\u043E\u0439 \u0438\u0437 \u043F\u044F\u0442\u0438\u0434\u0435\u0441\u044F\u0442\u0438 \u0431\u0443\u043A\u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0433\u043E \u0430\u043B\u0444\u0430\u0432\u0438\u0442\u0430].</p></blockquote><blockquote><p>\u041F\u0440\u0438 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0438, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u043C <em>(\u0101tmak\u0101t bhed\u0101t)</em> \u0438\u0437 b\u012Bja <em>(b\u012Bja)</em> [\u0438] yoni <em>(yoni)</em>, \u041E\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0434\u0432\u0443\u043C\u044F \u0441\u043F\u043E\u0441\u043E\u0431\u0430\u043C\u0438 <em>(dvidh\u0101)</em>. \u0413\u043B\u0430\u0441\u043D\u044B\u0435 <em>(svar\u0101\u1E25)</em> \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043A\u0430\u043A <em>(mat\u0101\u1E25)</em> b\u012Bja, \u0438\u043B\u0438 \u0441\u0435\u043C\u044F <em>(b\u012Bjam)</em>. \u041D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 ka, \u0438 \u0442.\u0434. <em>(ka-\u0101dibhi\u1E25)</em> \u043E \u041D\u0435\u0439 \u0433\u043E\u0432\u043E\u0440\u044F\u0442 \u043A\u0430\u043A \u043E <em>(sm\u1E5Bt\u0101)</em> yoni, \u0438\u043B\u0438 \u043B\u043E\u043D\u0435 <em>(yoni\u1E25)</em> --\u0442.\u0435. \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u044B\u0435 \u0441\u0447\u0438\u0442\u0430\u044E\u0442\u0441\u044F yoni--. [\u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E,] \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435\u043C <em>(bhedatas)</em> \u043D\u0430 varga-s, \u0438\u043B\u0438 \u0433\u0440\u0443\u043F\u043F\u044B \u0431\u0443\u043A\u0432 <em>(varga)</em>, [\u041E\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0434\u0435\u0432\u044F\u0442\u044C\u044E \u043F\u0443\u0442\u044F\u043C\u0438 <em>(navadh\u0101)</em><sup>1</sup>.</p></blockquote><blockquote><p>\u0412 \u044D\u0442\u043E\u043C [\u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435] <em>(atra)</em>, b\u012Bja --\u0433\u043B\u0430\u0441\u043D\u0430\u044F-- <em>(b\u012Bjam)</em> [\u0438] yoni --\u0441\u043E\u0433\u043B\u0430\u0441\u043D\u0430\u044F-- <em>(yoni\u1E25)</em> \u043D\u0430\u0437\u044B\u0432\u0430\u044E\u0442\u0441\u044F <em>(iti abhidh\u012Byate)</em> \u015Aiva <em>(\u015Biva\u1E25)</em> [\u0438] \u015Aakti <em>(\u015Bakti\u1E25)</em>. \u041A\u0441\u0442\u0430\u0442\u0438 <em>(ca)</em>, \u043F\u0440\u0438 \u0434\u0435\u043B\u0435\u043D\u0438\u0438 <em>(vibhedena)</em> \u043D\u0430 \u0432\u043E\u0441\u0435\u043C\u044C <em>(a\u1E63\u1E6Daka)</em> \u0433\u0440\u0443\u043F\u043F \u0431\u0443\u043A\u0432 <em>(varga)</em> [\u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E] \u0433\u0440\u0443\u043F\u043F\u0430 \u0438\u0437 \u0432\u043E\u0441\u044C\u043C\u0438 [\u0431\u043E\u0436\u0435\u0441\u0442\u0432] <em>(a\u1E63\u1E6Dakam)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] M\u0101he\u015Bvar\u012B <em>(m\u0101he\u015Bvar\u012B)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em> .</p></blockquote><blockquote><p>[\u0418] \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435\u043C \u0431\u0443\u043A\u0432 <em>(prativar\u1E47a-vibhedena)</em>, \u041E\u043D\u0430 \u0441\u0438\u044F\u0435\u0442 <em>(ujjval\u0101)</em> \u043A\u0430\u043A \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 <em>( \u015Bata-ardha)</em> \u043B\u0443\u0447\u0435\u0439 <em>(kira\u1E47a)</em> --\u0442.\u0435. \u041E\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 \u0431\u0443\u043A\u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0433\u043E \u0430\u043B\u0444\u0430\u0432\u0438\u0442\u0430--. \u042F\u0432\u043B\u044F\u044F\u0441\u044C \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u0435\u043C <em>(v\u0101cakatvena)</em> \u043D\u0430 Rudra-s <em>(rudr\u0101\u1E47\u0101m)</em>, \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u043A\u043E\u0442\u043E\u0440\u044B\u0445 <em>(sa\u1E45khy\u0101n\u0101m)</em> \u0442\u0430\u043A\u043E\u0435 \u0436\u0435 --\u0442.\u0435. \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442-- <em>(tad)</em>, \u041E\u043D\u0430 \u0443\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0430 [\u0432 \u044D\u0442\u043E\u043C \u0441\u0430\u043C\u043E\u043C \u0447\u0438\u0441\u043B\u0435] <em>(nive\u015Bit\u0101... iti)</em><sup>2</sup>&quot;||<br> [\u0421\u043C. M\u0101lin\u012Bvijayatantra III, 5-13]</p></blockquote><p>\u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C <em>(n\u012Bty\u0101)</em>, \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u043D\u044B\u043C \u0438 \u0443\u0434\u043E\u0441\u0442\u043E\u0432\u0435\u0440\u0435\u043D\u043D\u044B\u043C <em>(nir\u016Bpita)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C M\u0101lin\u012Bvijayatantra <em>(\u015Br\u012B-m\u0101lin\u012Bvijaya)</em>, \u0412\u044B\u0441\u0448\u0430\u044F \u0420\u0435\u0447\u044C <em>(par\u0101-v\u0101k)</em>, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0430\u044F\u0441\u044F \u043A \u0412\u044B\u0441\u0448\u0435\u043C\u0443 \u0413\u043E\u0441\u043F\u043E\u0434\u0443 <em>(p\u0101rame\u015Bvar\u012B)</em> --\u0442.\u0435. \u0415\u0433\u043E \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0435-- \u0440\u0430\u0437\u0432\u0435\u0440\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(prasarant\u012B)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0442\u043E\u0433\u043E <em>(\u015Britv\u0101)</em>, \u0447\u0442\u043E \u0441\u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u043E <em>(r\u016Bpat\u0101m)</em> \u0412\u043E\u043B\u0435\u0439 <em>(icch\u0101)</em>, \u0417\u043D\u0430\u043D\u0438\u0435\u043C <em>(j\xF1\u0101na)</em> [\u0438] \u0414\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C <em>(kriy\u0101)</em>. [\u041F\u043E\u0437\u0436\u0435, \u041E\u043D\u0430 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435], \u043F\u0440\u0438\u043D\u044F\u0432 \u0444\u043E\u0440\u043C\u0443 <em>(r\u016Bp\u0101)</em> \u0433\u043B\u0430\u0441\u043D\u044B\u0445 <em>(b\u012Bja)</em>, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u044B\u0445 <em>(yoni)</em>, \u0433\u0440\u0443\u043F\u043F \u0431\u0443\u043A\u0432 <em>(varga)</em>, \u0431\u0443\u043A\u0432, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0438\u0445 \u043A \u044D\u0442\u0438\u043C \u0433\u0440\u0443\u043F\u043F\u0430\u043C <em>(varg\u012B)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em> \u043F\u043E\u0441\u043B\u0435 \u043F\u0440\u0438\u043D\u044F\u0442\u0438\u044F <em>(\u015Britv\u0101)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(\u0101tmat\u0101m)</em> M\u0101t\u1E5Bk\u0101 <em>(m\u0101t\u1E5Bk\u0101)</em>, \u0447\u044C\u044F \u0444\u043E\u0440\u043C\u0430 <em>(r\u016Bp\u0101m)</em> \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0441 &quot;a&quot; <em>(a-\u0101di)</em> \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432 &quot;k\u1E63a&quot; <em>(k\u1E63a-anta)</em> --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0432\u0435\u0441\u044C \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0439 \u0430\u043B\u0444\u0430\u0432\u0438\u0442--, [\u0432\u0441\u0435 \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 --\u0442.\u0435. \u0432\u0441\u0435 \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 \u0431\u0443\u043A\u0432--] \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442 \u043D\u0430 <em>(v\u0101caka)</em> \u015Aiva <em>(\u015Biva)</em>, \u015Aakti <em>(\u015Bakti)</em>, M\u0101he\u015Bvar\u012B <em>(m\u0101he\u015Bvar\u012B)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em><sup>3</sup></p><p>. \u0412\u043E \u0432\u0441\u0435\u0445 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0445 <em>(sarva-pram\u0101t\u1E5B\u1E63u)</em><sup>4</sup>, \u043A\u043E\u0433\u0434\u0430 \u0438\u043C\u0435\u044E\u0442\u0441\u044F \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(tad-tad-da\u015B\u0101su)</em> \u0437\u043D\u0430\u043D\u0438\u044F <em>(sa\u1E41vedana)</em> \u0441 \u043C\u044B\u0441\u043B\u044F\u043C\u0438 <em>(savikalpaka)</em> [\u0438] \u0431\u0435\u0437 \u043C\u044B\u0441\u043B\u0435\u0439 <em>(avikalpaka)</em>, \u041E\u043D\u0430 \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442 <em>(vidadh\u0101n\u0101)</em>, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044F <em>(antar-par\u0101mar\u015Ba-\u0101tman\u0101)</em>, \u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u0435 --\u0442.\u0435. \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0441\u043B\u043E\u0432\u0430 \u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0442 \u0432\u043D\u0443\u0442\u0440\u044C-- <em>(anuvedhanam)</em> \u0433\u0440\u0443\u0431\u044B\u0445 <em>(sth\u016Bla)</em> [\u0438] \u0442\u043E\u043D\u043A\u0438\u0445 <em>(s\u016Bk\u1E63ma)</em> \u0441\u043B\u043E\u0432 <em>(\u015Babda)</em>. \u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(dv\u0101re\u1E47a)</em> \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F, \u0438\u043B\u0438 \u0441\u0438\u043B\u044B <em>(adhi\u1E63\u1E6Dh\u0101na)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em> \u0431\u043E\u0436\u0435\u0441\u0442\u0432 <em>(devat\u0101)</em> \u0433\u0440\u0443\u043F\u043F \u0431\u0443\u043A\u0432 <em>(varga)</em>, \u0431\u0443\u043A\u0432, \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0438\u0445 \u043A \u0442\u0430\u043A\u0438\u043C \u0433\u0440\u0443\u043F\u043F\u0430\u043C <em>(varg\u012B)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u041E\u043D\u0430 \u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u0443\u0435\u0442 <em>(prapa\xF1cayant\u012B)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(prapa\xF1cam)</em> \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u044F <em>(smaya)</em>, \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F <em>(har\u1E63a)</em>, \u0441\u0442\u0440\u0430\u0445\u0430 <em>(bhaya)</em>, \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0438 <em>(r\u0101ga)</em>, \u043E\u0442\u0432\u0440\u0430\u0449\u0435\u043D\u0438\u044F <em>(dve\u1E63a)</em> \u0438 \u0442\u043E\u043C\u0443 \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0435 <em>(\u0101di)</em>. [\u0418] \u0447\u0435\u0440\u0435\u0437 \u0441\u043E\u043A\u0440\u044B\u0442\u0438\u0435 <em>(\u0101v\u1E5B\u1E47v\u0101n\u0101)</em> \u0441\u0432\u043E\u0435\u0439 <em>(sva)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpam)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0435\u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u043D\u043E\u0439 --\u043D\u0435\u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u0439-- <em>(asa\u1E45kucita)</em> \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0439 <em>(svatantra)</em> \u043C\u0430\u0441\u0441\u043E\u0439 <em>(ghana)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em>, \u041E\u043D\u0430 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442 <em>(\u0101p\u0101dayati)</em> \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 <em>(mayatvam)</em> \u0441\u043E \u0441\u0436\u0430\u0442\u044B\u043C --\u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u043C-- <em>(sa\u1E45kucita)</em> \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u044B\u043C <em>(paratantra)</em> \u0442\u0435\u043B\u043E\u043C <em>(deha)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>|</p><p>\u042D\u0442\u043E <em>(tad)</em> \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Timirodgh\u0101\u1E6Da <em>(\u015Br\u012B-timirodgh\u0101\u1E6De)</em> too <em>(api)</em>:</p><blockquote><p>&quot;Mah\u0101ghor\u0101-s --\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, &quot;\u043E\u0447\u0435\u043D\u044C \u0441\u0442\u0440\u0430\u0448\u043D\u044B\u0435&quot;-- <em>(mah\u0101ghor\u0101\u1E25)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C, \u015Bakti-s, \u0438\u043B\u0438 \u0441\u0438\u043B\u044B], \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 <em>(sth\u0101\u1E25)</em> \u0432 \u0441\u0435\u0440\u0434\u0446\u0435\u0432\u0438\u043D\u0435 <em>(madhya)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(citi)</em> \u0432 Karandhra --\u0442.\u0435. \u0432 Brahmarandhra-- <em>(ka-randhra)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u043E\u0434\u0432\u0435\u0448\u0438\u0432\u0430\u044E\u0442 <em>(avalambik\u0101\u1E25)</em> \u0430\u0440\u043A\u0430\u043D\u043E\u043C \u0411\u0440\u0430\u0445\u043C\u044B <em>(brahma-p\u0101\u015Ba)</em> [\u0438] \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0412\u043B\u0430\u0434\u044B\u0447\u0438\u0446\u0430\u043C\u0438 <em>(\u012B\u015Bvarya\u1E25)</em> p\u012B\u1E6Dha-s, \u0438\u043B\u0438 \u043E\u043F\u043E\u0440/\u0441\u0438\u0434\u0435\u043D\u0438\u0439 --\u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432-- <em>(p\u012B\u1E6Dha)</em>, \u0432\u0432\u043E\u0434\u044F\u0442 \u0432 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435 <em>(mohayanti)</em> \u0432\u043D\u043E\u0432\u044C \u0438 \u0432\u043D\u043E\u0432\u044C <em>(muhur... muhur... iti)</em><sup>5</sup>&quot;||</p></blockquote><p>[\u0422\u043E, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043E \u0432\u044B\u0448\u0435] \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043E <em>(sa\u1E41v\u0101ditam)</em> \u0440\u0430\u043D\u0435\u0435 <em>(p\u016Brvam)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em> --\u0432 I, 4--|</p><p>&quot;\u041E\u0441\u043D\u043E\u0432\u043E\u0439 <em>(adhi\u1E63\u1E6Dh\u0101nam)</em> [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0438 \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u043D\u043E\u0433\u043E] \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043D\u0435\u043F\u043E\u043D\u044F\u0442\u0430\u044F \u041C\u0430\u0442\u044C <em>(m\u0101t\u1E5Bk\u0101)</em>. (I, 4) [\u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(1-4 iti)</em>&quot;. \u042D\u0442\u043E <em>(idam)</em> \u0431\u044B\u043B\u043E \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043E <em>(uktam... tu)</em> \u0432 \u043E\u0431\u0449\u0435\u043C \u0432\u0438\u0434\u0435 <em>(s\u0101m\u0101nyena)</em>. [\u0417\u0434\u0435\u0441\u044C, \u0432 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 --III, 19--, M\u0101t\u1E5Bk\u0101 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0431\u043E\u043B\u0435\u0435 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E], \u0441 \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u0438\u0435\u043C <em>(\u0101\u015Bayena)</em> [\u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C, \u0447\u0442\u043E] &quot;[\u0435\u0441\u043B\u0438] \u0434\u0430\u0436\u0435 <em>(api)</em> \u0442\u043E\u0442, \u043A\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0433 [\u0412\u044B\u0441\u0448\u0435\u0433\u043E] \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0430 <em>(pr\u0101pta-tattva\u1E25)</em>, \u043D\u0435 \u043E\u0441\u0442\u043E\u0440\u043E\u0436\u0435\u043D \u0438 \u043D\u0435 \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u0435\u043D <em>(pram\u0101dyan)</em>, \u0442\u0430\u043A\u0436\u0435 \u0432\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435 <em>(api... mohyate)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C M\u0101he\u015B\u012B --\u0438\u043B\u0438 M\u0101he\u015Bvar\u012B--, \u0438 \u0442.\u0434. <em>(m\u0101he\u015B\u012B-\u0101dibhi\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(bh\u016Bt\u0101bhi\u1E25)</em> [\u0431\u043E\u0433\u0438\u043D\u044F\u043C\u0438], \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u0438\u0440\u0443\u044E\u0449\u0438\u043C\u0438 <em>(adhi\u1E63\u1E6Dh\u0101t\u1E5B)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 \u043B\u044E\u0434\u0435\u0439 <em>(pa\u015Bu-jana)</em> \u043F\u0443\u0442\u0435\u043C \u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u044F --\u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F-- <em>(anuvedha-dv\u0101re\u1E47a)</em> \u0441\u043B\u043E\u0432 <em>(\u015Babda... iti)</em>&quot;. \u0412 \u044D\u0442\u043E\u043C \u0440\u0430\u0437\u043D\u0438\u0446\u0430 <em>(iti vi\u015Be\u1E63a\u1E25)</em> [\u043C\u0435\u0436\u0434\u0443 \u0434\u0432\u0443\u043C\u044F \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F\u043C\u0438 --\u0430\u043D\u0430\u043B\u0438\u0437\u043E\u043C, \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043D\u043E\u043C \u0432 I, 4 \u0438 \u0432 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435--]||19||</p><hr><ol><li>\u0421\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0439 \u0430\u043B\u0444\u0430\u0432\u0438\u0442 \u0432 \u0435\u0433\u043E \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043E\u043D\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435 \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 8 varga-s, \u0438\u043B\u0438 \u0433\u0440\u0443\u043F\u043F \u0431\u0443\u043A\u0432:</li></ol><ul><li><p>A-varga (\u0413\u043B\u0430\u0441\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 Yog\u012B\u015Bvar\u012B (\u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u0430\u044F Mah\u0101lak\u1E63m\u012B)</p></li><li><p>Ka-varga (\u0413\u043E\u0440\u0442\u0430\u043D\u043D\u044B\u0435/\u0437\u0430\u0434\u043D\u0435\u044F\u0437\u044B\u0447\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 Br\u0101hm\u012B</p></li><li><p>Ca-varga (\u041F\u0430\u043B\u0430\u0442\u0430\u043B\u044C\u043D\u044B\u0435/\u041D\u0435\u0431\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 M\u0101he\u015Bvar\u012B</p></li><li><p>\u1E6Ca-varga (\u0426\u0435\u0440\u0435\u0431\u0440\u0430\u043B\u044C\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 Kaum\u0101r\u012B</p></li><li><p>Ta-varga (\u0417\u0443\u0431\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 Vai\u1E63\u1E47av\u012B</p></li><li><p>Pa-varga (\u0413\u0443\u0431\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 V\u0101rah\u012B</p></li><li><p>Ya-varga (\u041D\u0435\u043D\u043E\u0441\u043E\u0432\u044B\u0435 \u0441\u043E\u043D\u0430\u043D\u0442\u044B/\u043F\u043E\u043B\u0443\u0433\u043B\u0430\u0441\u043D\u044B\u0435), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 Aindr\u012B (\u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u0430\u044F Indr\u0101\u1E47\u012B)</p></li><li><p>\u015Aa-varga (\u0428\u0438\u043F\u044F\u0449\u0438\u0435, \u043F\u0440\u0438\u0434\u044B\u0445\u0430\u0442\u0435\u043B\u044C\u043D\u0430\u044F \u0441\u043E\u043D\u0430\u043D\u0442\u0430 + K\u016B\u1E6Dab\u012Bja --\u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u043D\u0430\u044F k\u1E63a, \u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u0438\u0437 &quot;ka + sa&quot;, \u043D\u043E \u043E\u0447\u0435\u043D\u044C \u0447\u0430\u0441\u0442\u043E \u0441\u0447\u0438\u0442\u0430\u044E\u0449\u0430\u044F\u0441\u044F \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0439 \u0431\u0443\u043A\u0432\u043E\u0439--), \u0433\u0434\u0435 \u043F\u0440\u0430\u0432\u044F\u0449\u0430\u044F \u0431\u043E\u0433\u0438\u043D\u044F \u2014 C\u0101mu\u1E47\u1E0D\u0101</p><p>\u0412 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0432\u0440\u0435\u043C\u044F \u0430\u043B\u0444\u0430\u0432\u0438\u0442, \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u043D\u044B\u0439 \u0432 \u0435\u0433\u043E \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043E\u043D\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435, \u043D\u0435 \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 K\u016B\u1E6Dab\u012Bja (\u0431\u0443\u043A\u0432\u0443 k\u1E63a), \u043D\u043E \u043A\u043E\u0433\u0434\u0430 \u044D\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442, K\u016B\u1E6Dab\u012Bja \u043E\u0431\u044B\u0447\u043D\u043E \u043F\u0440\u0438\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043A \u0432\u043E\u0441\u044C\u043C\u043E\u0439 varga, \u0438\u043B\u0438 \u0433\u0440\u0443\u043F\u043F\u0435 (\u015Aa-varga). \u0418\u0442\u0430\u043A, \u0432\u043E\u043F\u0440\u043E\u0441 \u043D\u0430 \u043C\u0438\u043B\u043B\u0438\u043E\u043D: &quot;\u0415\u0441\u043B\u0438 \u0438\u043C\u0435\u0435\u0442\u0441\u044F 8 varga-s, \u0438\u043B\u0438 \u0433\u0440\u0443\u043F\u043F, \u043F\u043E\u0447\u0435\u043C\u0443 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0433\u043E\u0432\u043E\u0440\u0438\u043B \u043E\u0431 \u044D\u0442\u043E\u043C \u0432\u044B\u0448\u0435?: &quot; [\u0414\u0430 \u043F\u043E\u0442\u043E\u043C\u0443, \u0447\u0442\u043E] \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435\u043C varga-s, \u0438\u043B\u0438 \u0433\u0440\u0443\u043F\u043F \u0431\u0443\u043A\u0432, [\u041E\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0434\u0435\u0432\u044F\u0442\u044C\u044E \u043F\u0443\u0442\u044F\u043C\u0438. \u0423\u043F\u0440\u043E\u0449\u0435\u043D\u043D\u043E: \u0438\u043D\u043E\u0433\u0434\u0430 K\u016B\u1E6Dab\u012Bja \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0439 varga, \u0442.\u0435. K\u1E63a-varga. \u0412 \u044D\u0442\u043E\u043C \u043E\u0441\u043E\u0431\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u043E\u0431\u0449\u0435\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E varga-s \u0431\u0443\u0434\u0435\u0442 \u0440\u0430\u0432\u043D\u043E 9, \u0430 \u043D\u0435 8. \u0422\u0435\u043F\u0435\u0440\u044C, \u044D\u0442\u0430 \u0447\u0430\u0441\u0442\u044C \u0442\u0435\u043A\u0441\u0442\u0430 \u043F\u043E\u043D\u044F\u0442\u043D\u0430, \u0442\u0430\u043A \u0432\u0435\u0434\u044C?</p></li></ul><ol start="2"><li><p>\u0427\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u043D\u044F\u0442\u044C \u044D\u0442\u043E\u0442 \u0432\u043E\u043F\u0440\u043E\u0441, \u0438 \u0443\u0447\u0438\u0442\u0435\u043B\u044C, \u0438 \u0443\u0447\u0435\u043D\u0438\u043A \u0434\u043E\u043B\u0436\u043D\u044B \u0431\u044B\u0442\u044C \u043E\u0447\u0435\u043D\u044C \u0445\u043E\u0440\u043E\u0448\u043E \u0437\u043D\u0430\u043A\u043E\u043C\u044B \u0441\u043E \u0437\u043D\u0430\u043D\u0438\u044F\u043C\u0438, \u043E\u0442\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u043D\u044B\u043C\u0438 \u0432 M\u0101lin\u012Bvijayatantra. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u0437\u0434\u0435\u0441\u044C \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F: \u0418\u043D\u0434\u0438\u043A\u0430\u0442\u043E\u0440/\u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E \u041E\u043D\u0430 \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0438\u043B\u0438 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 Rudra-s, \u0438\u043B\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432, \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0449\u0438\u0445 \u043A\u0430\u0436\u0434\u0443\u044E \u0438\u0437 \u043F\u044F\u0442\u0438\u0434\u0435\u0441\u044F\u0442\u0438 \u0431\u0443\u043A\u0432 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u043E\u0433\u043E \u0430\u043B\u0444\u0430\u0432\u0438\u0442\u0430. \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0441\u0434\u0435\u043B\u0430\u043B \u0415\u0435 \u0442\u0430\u043A\u043E\u0439, \u0442.\u0435. \u043F\u044F\u0442\u0438\u0434\u0435\u0441\u044F\u0442\u0438-\u043A\u0440\u0430\u0442\u043D\u043E\u0439, \u0438 \u0432\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u041E\u043D\u0430 \u0443\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0430 \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u0435. \u041F\u043E\u043C\u0438\u043C\u043E Rudra-s \u0438\u043C\u0435\u044E\u0442\u0441\u044F \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 \u0441\u0443\u043F\u0440\u0443\u0433 \u0434\u043B\u044F \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0438\u0437 \u043D\u0438\u0445, \u0442.\u0435. \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 Rudr\u0101\u1E47\u012B-s. \u0410\u0445, \u044D\u0442\u043E\u0442 \u043F\u0440\u0435\u0434\u043C\u0435\u0442 \u2014 \u043E\u0447\u0435\u043D\u044C \u0434\u043B\u0438\u043D\u043D\u044B\u0439 \u0438 \u0441\u043B\u043E\u0436\u043D\u044B\u0439. \u0414\u043B\u044F \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F \u0431\u043E\u043B\u0435\u0435 \u0434\u0435\u0442\u0430\u043B\u044C\u043D\u043E\u0439 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438, \u0432\u044B \u0432\u0441\u0435\u0433\u0434\u0430 \u043C\u043E\u0436\u0435\u0442\u0435 \u043E\u0431\u0440\u0430\u0442\u0438\u0442\u044C\u0441\u044F \u043A &quot;\u041F\u0438\u0441\u0430\u043D\u0438\u044F (\u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435)/\u015Aivas\u016Btravimar\u015Bin\u012B&quot; \u0432 \u0440\u0430\u0437\u0434\u0435\u043B\u0435 \u0422\u0440\u0438\u043A\u0430.</p></li><li><p>\u0427\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u044C \u0431\u043E\u043B\u044C\u0448\u0435 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u043E\u0431\u043E \u0432\u0441\u0435\u043C \u044D\u0442\u043E\u043C, \u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u043C\u043E\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435 \u0432 II, 7 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F.</p></li><li><p>\u0418\u043C\u0435\u0435\u0442\u0441\u044F \u0441\u0435\u043C\u044C \u0442\u0438\u043F\u043E\u0432 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0445, \u0438\u043B\u0438 \u0441\u043A\u043E\u0440\u0435\u0435 \u0441\u0435\u043C\u044C \u044D\u0442\u0430\u043F\u043E\u0432 \u0434\u043B\u044F \u043E\u0434\u043D\u043E\u0433\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0435\u0433\u043E:</p><ol><li>\u015Aiva (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E \u015Aiva \u0438 \u015Aakti \u0442\u0430\u0442\u0442\u0432\u044B, \u043F\u0435\u0440\u0432\u044B\u0435 \u0434\u0432\u0435 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438);</li><li>Mantramahe\u015Bvara (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E Sad\u0101\u015Biva-\u0442\u0430\u0442\u0442\u0432\u0430, \u0442\u0440\u0435\u0442\u044C\u044F \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F);</li><li>Mantre\u015Bvara (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E \u012A\u015Bvara-\u0442\u0430\u0442\u0442\u0432\u0430, \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0430\u044F \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F);</li><li>Mantra (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E Sadvidy\u0101, \u0438\u043B\u0438 \u015Auddhavidy\u0101 \u0442\u0430\u0442\u0442\u0432\u0430, \u043F\u044F\u0442\u0430\u044F \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F);</li><li>Vij\xF1\u0101n\u0101kala (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043C\u0435\u0436\u0434\u0443 Sadvidy\u0101 \u0438 M\u0101y\u0101 \u0442\u0430\u0442\u0442\u0432\u0430\u043C\u0438, \u0442.\u0435. \u043C\u0435\u0436\u0434\u0443 \u043F\u044F\u0442\u043E\u0439 \u0438 \u0448\u0435\u0441\u0442\u043E\u0439 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F\u043C\u0438);</li><li>Pralay\u0101kala (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u044D\u0442\u043E M\u0101y\u0101 \u0438 \u0435\u0435 \u043F\u044F\u0442\u044C Ka\xF1cuka-s, \u0441 \u0448\u0435\u0441\u0442\u043E\u0439 \u043F\u043E \u043E\u0434\u0438\u043D\u043D\u0430\u0434\u0446\u0430\u0442\u0443\u044E \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438);</li><li>Sakala (\u0435\u0433\u043E \u0441\u0444\u0435\u0440\u0430 \u2014 \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 Puru\u1E63a --\u0434\u0432\u0435\u043D\u0430\u0434\u0446\u0430\u0442\u043E\u0439 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438-- \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0439).</li></ol></li><li><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u0430 \u0441\u0442\u0440\u043E\u0444\u0430, \u043A\u043E\u0442\u043E\u0440\u0443\u044E \u044F \u043F\u0435\u0440\u0435\u0432\u043E\u0436\u0443, \u0446\u0438\u0442\u0438\u0440\u043E\u0432\u0430\u043B\u0430\u0441\u044C \u0440\u0430\u043D\u0435\u0435 K\u1E63emar\u0101ja \u0432 I, 4 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F, \u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u0442\u0430\u043C \u043F\u043E\u044F\u0441\u043D\u0435\u043D\u0438\u0435 2, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043D\u044F\u0442\u044C \u0435\u0435 \u0441\u043C\u044B\u0441\u043B.</p></li></ol></div>',1),v=[r];function p(d,h,n,o,u,s){return m(),e("div",null,v)}var l=a(i,[["render",p]]);export{k as __pageData,l as default};
